def bridge(manager_name):
    return f"""# -*- coding: utf-8 -*-
import sys
from pathlib import Path
PACKAGE_DIR = Path(__file__).resolve().parent / "205"
sys.path.insert(0, str(PACKAGE_DIR))
from {manager_name} import main
if __name__ == "__main__":
    main()
"""

def manager_code(module_name, class_name, title):
    return f"""# -*- coding: utf-8 -*-
import argparse
from engines.{module_name} import {class_name}

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--run", action="store_true")
    parser.add_argument("--status", action="store_true")
    args = parser.parse_args()
    res = {class_name}().run()
    result = res["result"]
    print("="*80)
    print("{title} TAMAMLANDI")
    print("="*80)
    print(f"Score    : {result['score']} / 100")
    print(f"Decision : {result['decision']}")
    print(f"Risk     : {result['risk']}")
    print("")
    print("Recommendation:")
    print(result["recommendation"])
    print("")
    print("Dosyalar:")
    print(res["paths"]["output"])
    print(res["paths"]["report"])

if __name__ == "__main__":
    main()
"""

def main():
    if not (PKG / "core").exists():
        raise SystemExit("205 Intelligence SDK bulunamadı. Önce SDK kurulmalı.")
    ENGINES_DIR.mkdir(parents=True, exist_ok=True)
    (ENGINES_DIR / "__init__.py").write_text("", encoding="utf-8")

    for module_name, engine_code in ENGINES.items():
        class_name, title, manager_name, bridge_file = MANAGERS[module_name]
        engine_path = ENGINES_DIR / f"{module_name}.py"
        manager_path = PKG / f"{manager_name}.py"
        bridge_path = PY / bridge_file
        engine_path.write_text(engine_code, encoding="utf-8")
        manager_path.write_text(manager_code(module_name, class_name, title), encoding="utf-8")
        bridge_path.write_text(bridge(manager_name), encoding="utf-8")
        py_compile.compile(str(engine_path), doraise=True)
        py_compile.compile(str(manager_path), doraise=True)
        py_compile.compile(str(bridge_path), doraise=True)

    run_all_path = PY / "205_Intelligence_Run_All.py"
    run_all_path.write_text(RUN_ALL, encoding="utf-8")
    py_compile.compile(str(run_all_path), doraise=True)

    print("="*80)
    print("205.6–205.10 INTELLIGENCE BATCH BUILDER TAMAMLANDI")
    print("="*80)
    print("Oluşturulan motor sayısı : 5")
    print("Run All dosyası          :", run_all_path)
    print("")
    print("Şimdi çalıştır:")
    print(r'python ".py\205_Intelligence_Run_All.py"')

if __name__ == "__main__":
    main()
